class Solution(object):
    def minimumPairRemoval(self, nums):
        nums = list(nums)
        ops = 0
        while nums != sorted(nums):
            min_sum = float('inf')
            min_i = 0
            for i in range(len(nums) - 1):
                if nums[i] + nums[i + 1] < min_sum:
                    min_sum = nums[i] + nums[i + 1]
                    min_i = i
            nums[min_i] = min_sum
            nums.pop(min_i + 1)
            ops += 1
        return ops
